var findSmallestInteger = function(nums, value) {
    const cnt = new Map();
    for (const x of nums) {
        const r = ((x % value) + value) % value;
        cnt.set(r, (cnt.get(r) || 0) + 1);
    }
    let t = 0;
    while ((cnt.get(t % value) || 0) > 0) {
        cnt.set(t % value, cnt.get(t % value) - 1);
        t += 1;
    }
    return t;
};
